        "parser-extract-function": {
          "highlightedHtml": "<pre class=\"shiki github-dark\" style=\"background-color:#24292e;color:#e1e4e8\" tabindex=\"0\"><code><span class=\"line\"><span style=\"color:#F97583\">def</span><span style=\"color:#B392F0\"> extract_text_from_pdf</span><span style=\"color:#E1E4E8\">(pdf_bytes: </span><span style=\"color:#79B8FF\">bytes</span><span style=\"color:#E1E4E8\">) -> </span><span style=\"color:#79B8FF\">str</span><span style=\"color:#E1E4E8\">:</span></span>\n<span class=\"line\"><span style=\"color:#79B8FF\">    MSG</span><span style=\"color:#F97583\"> =</span><span style=\"color:#9ECBFF\"> \"Could not extract text from the PDF. The file may be corrupted or image-only.\"</span></span>\n<span class=\"line\"></span>\n<span class=\"line\"><span style=\"color:#F97583\">    try</span><span style=\"color:#E1E4E8\">:</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">        reader </span><span style=\"color:#F97583\">=</span><span style=\"color:#E1E4E8\"> PdfReader(BytesIO(pdf_bytes))</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">        parts </span><span style=\"color:#F97583\">=</span><span style=\"color:#E1E4E8\"> []</span></span>\n<span class=\"line\"><span style=\"color:#F97583\">        for</span><span style=\"color:#E1E4E8\"> page </span><span style=\"color:#F97583\">in</span><span style=\"color:#E1E4E8\"> reader.pages:</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">            text </span><span style=\"color:#F97583\">=</span><span style=\"color:#E1E4E8\"> page.extract_text()</span></span>\n<span class=\"line\"><span style=\"color:#F97583\">            if</span><span style=\"color:#E1E4E8\"> text:</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">                parts.append(text)</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">        full_text </span><span style=\"color:#F97583\">=</span><span style=\"color:#9ECBFF\"> \"</span><span style=\"color:#79B8FF\">\\n</span><span style=\"color:#9ECBFF\">\"</span><span style=\"color:#E1E4E8\">.join(parts).strip()</span></span>\n<span class=\"line\"><span style=\"color:#F97583\">    except</span><span style=\"color:#79B8FF\"> Exception</span><span style=\"color:#F97583\"> as</span><span style=\"color:#E1E4E8\"> e:</span></span>\n<span class=\"line\"><span style=\"color:#F97583\">        raise</span><span style=\"color:#E1E4E8\"> PDFExtractionError(</span><span style=\"color:#79B8FF\">MSG</span><span style=\"color:#E1E4E8\">) </span><span style=\"color:#F97583\">from</span><span style=\"color:#E1E4E8\"> e</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">    </span></span>\n<span class=\"line\"><span style=\"color:#F97583\">    if</span><span style=\"color:#F97583\"> not</span><span style=\"color:#E1E4E8\"> full_text:</span></span>\n<span class=\"line\"><span style=\"color:#F97583\">        raise</span><span style=\"color:#E1E4E8\"> PDFExtractionError(</span><span style=\"color:#79B8FF\">MSG</span><span style=\"color:#E1E4E8\">)</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">    </span></span>\n<span class=\"line\"><span style=\"color:#F97583\">    return</span><span style=\"color:#E1E4E8\"> full_text</span></span></code></pre>"
        }
